mapper.select:
SELECT id, name, http_method, endpoint, version, status, description, created_at, updated_at
FROM pgdev.api_endpoints
WHERE id = #{id}

SELECT id, name, http_method, endpoint, version, status, description, created_at, updated_at
FROM pgdev.api_endpoints
WHERE endpoint = #{endpoint}

SELECT id, name, http_method, endpoint, version, status, description, created_at, updated_at
FROM pgdev.api_endpoints
WHERE name = #{name}
  AND version = #{version}

mapper.update:
UPDATE pgdev.api_definitions
SET api_name = #{apiName},
    updated_at = #{updatedAt}
WHERE id = #{id}
